import java.io.*;
import java.util.*;

public class Main {
    static class Edge implements Comparable<Edge> {
        int u, v, w;
        Edge(int u, int v, int w) {
            this.u = u;
            this.v = v;
            this.w = w;
        }
        public int compareTo(Edge o) {
            if (this.w != o.w) return Integer.compare(this.w, o.w);
            if (this.u != o.u) return Integer.compare(this.u, o.u);
            return Integer.compare(this.v, o.v);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String firstLine = br.readLine();
        if (firstLine == null || firstLine.trim().isEmpty()) {
            // No input provided
            return;
        }
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(firstLine.trim());
        while (T-- > 0) {
            String line;
            // skip possible empty lines
            do {
                line = br.readLine();
            } while (line != null && line.trim().isEmpty());
            if (line == null) break;
            StringTokenizer st = new StringTokenizer(line);
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            List<Edge>[] adj = new ArrayList[n + 1];
            for (int i = 1; i <= n; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < m; i++) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                int w = Integer.parseInt(st.nextToken());
                adj[u].add(new Edge(u, v, w));
                adj[v].add(new Edge(v, u, w));
            }
            boolean[] vis = new boolean[n + 1];
            PriorityQueue<Edge> pq = new PriorityQueue<>();
            List<int[]> mstEdges = new ArrayList<>();
            long totalWeight = 0;
            // start from vertex 1
            vis[1] = true;
            for (Edge e : adj[1]) pq.offer(e);
            while (!pq.isEmpty() && mstEdges.size() < n - 1) {
                Edge e = pq.poll();
                int from = -1, to = -1;
                if (vis[e.u] && !vis[e.v]) {
                    from = e.u;
                    to = e.v;
                } else if (!vis[e.u] && vis[e.v]) {
                    from = e.v;
                    to = e.u;
                } else {
                    continue; // both visited or both unvisited
                }
                vis[to] = true;
                totalWeight += e.w;
                mstEdges.add(new int[]{from, to});
                for (Edge ne : adj[to]) {
                    if (!vis[ne.v]) pq.offer(ne);
                }
            }
            out.append(totalWeight).append('\n');
            for (int[] e : mstEdges) {
                out.append(e[0]).append(' ').append(e[1]).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

